// 1. Obtenemos el texto sucio que viene del LLM
const rawText = $input.first().json.text

// 2. Limpiamos las etiquetas de markdown (```json y ```) y espacios extra
const cleanJsonString = rawText
    .replace(/```json/g, '') // Quita el inicio del bloque
    .replace(/```/g, '')     // Quita el final del bloque
    .trim();                 // Quita espacios en blanco al inicio y final

// 3. Convertimos el texto limpio a un Objeto real
let parsedData;
try {
    parsedData = JSON.parse(cleanJsonString);
} catch (error) {
    // Si falla (por si acaso el LLM alucina), devolvemos un fallback
    parsedData = { intent: "other", reason: "Error de parsing" };
}

// 4. Devolvemos los datos limpios para que el Switch los entienda
return {
    json: parsedData
};

